SELECT farm_name
FROM farms
ORDER BY farm_name;

SELECT farm_name
FROM farms
WHERE total_sheep = (SELECT MAX(total_sheep) FROM farms);

SELECT farm_name
FROM farms
WHERE total_sheep = (
    SELECT MAX(total_sheep)
    FROM farms
);

SELECT f.farm_name, sc.total_sheep
FROM farms f
JOIN sheep_counts sc ON f.farm_id = sc.farm_id
WHERE sc.total_sheep = (
    SELECT MAX(subq.total_sheep)
    FROM (
        SELECT sc2.farm_id, sc2.total_sheep
        FROM sheep_counts sc2
    ) subq
);

SELECT farm_name
FROM farms
WHERE farm_id IN (SELECT farm_id FROM sheep_counts);
